package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import java.lang.reflect.Field;
import java.lang.reflect.Modifier;

class CSVFormatIsNullStringSetTest {

    private CSVFormat setNullStringField(CSVFormat original, String nullString) throws Exception {
        // Use withNullString method to create a new CSVFormat instance with the desired nullString
        return original.withNullString(nullString);
    }

    @Test
    void testIsNullStringSet_whenNullStringIsNull() throws Exception {
        CSVFormat format = CSVFormat.DEFAULT;
        CSVFormat newFormat = setNullStringField(format, null);

        assertFalse(newFormat.isNullStringSet());
    }

    @Test
    void testIsNullStringSet_whenNullStringIsNonNull() throws Exception {
        CSVFormat format = CSVFormat.DEFAULT;
        CSVFormat newFormat = setNullStringField(format, "NULL");

        assertTrue(newFormat.isNullStringSet());
    }
}
